import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 25 — Text Objects: iw and aw","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/25-text-objects-iw-aw.md","filePath":"chapters/25-text-objects-iw-aw.md"}'),n={name:"chapters/25-text-objects-iw-aw.md"};function d(i,e,r,c,l,p){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="chapter-25-—-text-objects-iw-and-aw" tabindex="-1">Chapter 25 — Text Objects: iw and aw <a class="header-anchor" href="#chapter-25-—-text-objects-iw-and-aw" aria-label="Permalink to &quot;Chapter 25 — Text Objects: iw and aw&quot;">​</a></h1><blockquote><p><em>&quot;Text objects let you operate on structural units of text rather than arbitrary ranges.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐⭐ Intermediate <strong>Estimated Reading Time:</strong> 20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Text objects are one of Vim&#39;s most powerful features.</p><p>Instead of thinking &quot;delete from character 3 to character 8,&quot;</p><p>you think &quot;delete this word&quot; or &quot;change inside these quotes.&quot;</p><hr><h1 id="what-is-a-text-object" tabindex="-1">What Is a Text Object? <a class="header-anchor" href="#what-is-a-text-object" aria-label="Permalink to &quot;What Is a Text Object?&quot;">​</a></h1><p>A <strong>text object</strong> is a structural unit of text:</p><ul><li>A word</li><li>A sentence</li><li>A paragraph</li><li>Text inside quotes</li><li>Text inside parentheses</li><li>Text inside brackets</li></ul><hr><h1 id="the-two-prefixes" tabindex="-1">The Two Prefixes <a class="header-anchor" href="#the-two-prefixes" aria-label="Permalink to &quot;The Two Prefixes&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Prefix</th><th>Meaning</th><th>Includes Boundaries?</th></tr></thead><tbody><tr><td><code>i</code></td><td><strong>inner</strong></td><td>No (inside only)</td></tr><tr><td><code>a</code></td><td><strong>a</strong></td><td>Yes (includes surrounding whitespace/delimiters)</td></tr></tbody></table><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>
<span class="line"><span>     ^</span></span>
<span class="line"><span></span></span>
<span class="line"><span>diw   →   deletes &quot;World&quot; (no space)</span></span>
<span class="line"><span>daw   →   deletes &quot;World &quot; (includes the space)</span></span></code></pre></div><hr><h1 id="word-text-objects" tabindex="-1">Word Text Objects <a class="header-anchor" href="#word-text-objects" aria-label="Permalink to &quot;Word Text Objects&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>diw</code></td><td>Delete <strong>inner word</strong></td></tr><tr><td><code>daw</code></td><td>Delete <strong>a word</strong> (includes space)</td></tr><tr><td><code>ciw</code></td><td>Change inner word</td></tr><tr><td><code>caw</code></td><td>Change a word</td></tr><tr><td><code>yiw</code></td><td>Yank inner word</td></tr><tr><td><code>yaw</code></td><td>Yank a word</td></tr></tbody></table><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>function calculateTotal() {</span></span>
<span class="line"><span>                ^</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ciw → change inner word</span></span>
<span class="line"><span>Type &quot;compute&quot; →</span></span>
<span class="line"><span></span></span>
<span class="line"><span>function computeTotal() {</span></span></code></pre></div><hr><h1 id="why-text-objects-matter" tabindex="-1">Why Text Objects Matter <a class="header-anchor" href="#why-text-objects-matter" aria-label="Permalink to &quot;Why Text Objects Matter&quot;">​</a></h1><p>Without text objects:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dword    →   deletes from cursor to next word (not the whole word)</span></span></code></pre></div><p>With text objects:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>diw      →   deletes the entire word under cursor</span></span></code></pre></div><p>The difference is crucial when the cursor is in the middle of a word.</p><hr><h1 id="practice" tabindex="-1">Practice <a class="header-anchor" href="#practice" aria-label="Permalink to &quot;Practice&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The quick brown fox</span></span>
<span class="line"><span>      ^</span></span>
<span class="line"><span></span></span>
<span class="line"><span>diw → &quot;The  brown fox&quot; (deletes &quot;quick&quot;)</span></span>
<span class="line"><span>daw → &quot;The brown fox&quot; (deletes &quot;quick &quot; including space)</span></span>
<span class="line"><span>ciw → &quot;The  brown fox&quot; (insert mode, &quot;quick&quot; deleted)</span></span></code></pre></div><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>diw</code></td><td>Delete inner word</td></tr><tr><td><code>daw</code></td><td>Delete a word (with space)</td></tr><tr><td><code>ciw</code></td><td>Change inner word</td></tr><tr><td><code>caw</code></td><td>Change a word</td></tr><tr><td><code>yiw</code></td><td>Yank inner word</td></tr><tr><td><code>yaw</code></td><td>Yank a word</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>i</code> = inner (without surrounding whitespace/delimiters).</li><li><code>a</code> = a (includes surrounding whitespace/delimiters).</li><li>Text objects work with all operators: <code>d</code>, <code>c</code>, <code>y</code>, <code>v</code>, <code>gu</code>, <code>gU</code>, etc.</li><li>Use <code>iw</code> for precise word editing regardless of cursor position.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a file and practice <code>diw</code> on words.</li><li>Compare <code>diw</code> vs <code>daw</code> to see the space difference.</li><li>Use <code>ciw</code> to replace words without deleting surrounding punctuation.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./26-text-objects-parentheses.html"><strong>Chapter 26 — Text Objects: Parentheses</strong></a></p><p>Edit text inside parentheses with surgical precision.</p>`,46)])])}const b=t(n,[["render",d]]);export{u as __pageData,b as default};
